mapper.select:
SELECT es.id, es.exam_id, e.course_id, e.exam_title as examTitle, e.exam_type, es.student_id, es.start_time, es.submit_time, es.answers, es.total_score, es.status, es.created_time FROM exam_submission es LEFT JOIN exam e ON es.exam_id = e.id
AND es.student_id = #{q.studentId}
AND e.exam_type = #{q.examType}
AND e.course_id = #{q.courseId}
ORDER BY es.submit_time DESC, es.created_time DESC

SELECT es.id, es.exam_id, e.course_id, e.exam_title AS examTitle, e.exam_type, es.student_id, es.start_time, es.submit_time, es.answers, es.total_score, es.status, es.created_time FROM exam_submission es INNER JOIN exam e ON es.exam_id = e.id
AND e.teacher_id = #{q.teacherId}
AND es.exam_id = #{q.examId}
AND e.course_id = #{q.courseId}
AND e.exam_type = #{q.examType}
AND es.status = #{q.status}
ORDER BY
es.start_time
es.total_score
es.submit_time
ASC
DESC
